# ruff: noqa: E501
"""Static presentation generator; it does not alter the research dataset."""
from __future__ import annotations

import copy
import json
from pathlib import Path
from typing import Any


def write_html(rows: list[dict[str, Any]], path: Path) -> None:
    display_rows = copy.deepcopy(rows)
    for row in display_rows:
        row["unresolved_fields"] = [
            value for value in row.get("unresolved_fields", [])
            if not any(token in value.lower() for token in ("normalization:", "modelquota", "schema repair", "extraction retry", "provider error"))
        ]
    data = json.dumps(display_rows, ensure_ascii=False).replace("</", "<\\/")
    template = """<!doctype html>
<html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<title>Composio Agent Operations Case Study</title>
<style>
:root{--bg:#090b0d;--panel:#111518;--line:#273035;--text:#f7f5ed;--muted:#9ca7a8;--lime:#c8ff39}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font:15px Inter,system-ui,sans-serif;background-image:linear-gradient(#ffffff05 1px,transparent 1px),linear-gradient(90deg,#ffffff05 1px,transparent 1px);background-size:32px 32px}main{max-width:1400px;margin:auto;padding:32px 5vw 120px}h1{font-size:clamp(2.5rem,7vw,6rem);line-height:.96;max-width:900px;margin:18px 0}h2{font-size:2rem;margin-top:72px}.eyebrow,.mono{font:12px ui-monospace,monospace;letter-spacing:.12em;color:var(--lime);text-transform:uppercase}.lede{font-size:1.2rem;color:var(--muted);max-width:700px;line-height:1.6}.actions{display:flex;gap:12px;margin:28px 0}.btn{border:1px solid var(--line);background:var(--panel);color:var(--text);padding:12px 18px;border-radius:999px;cursor:pointer}.btn.primary{background:var(--lime);color:#111;border-color:var(--lime)}.cards{display:grid;grid-template-columns:repeat(4,1fr);gap:12px}.card,.finding,.method{background:#111518dd;border:1px solid var(--line);border-radius:16px;padding:22px}.metric{font-size:2rem;font-weight:800}.muted{color:var(--muted)}.finding{margin-top:32px;font-size:1.45rem;max-width:1000px}.finding small{display:block;font-size:1rem;color:var(--muted);line-height:1.6;margin-top:14px}.controls{display:flex;flex-wrap:wrap;gap:8px;margin:20px 0}.controls input,.controls select{background:var(--panel);color:var(--text);border:1px solid var(--line);padding:10px;border-radius:8px}table{width:100%;border-collapse:separate;border-spacing:0 6px}th{font:11px ui-monospace,monospace;color:var(--muted);text-align:left;padding:8px;text-transform:uppercase}td{background:var(--panel);padding:13px 8px;border-top:1px solid var(--line);border-bottom:1px solid var(--line)}td:first-child{border-left:1px solid var(--line);border-radius:10px 0 0 10px}td:last-child{border-right:1px solid var(--line);border-radius:0 10px 10px 0}.final td{background:#17200f}.badge{display:inline-block;padding:4px 8px;border-radius:999px;background:#263035;color:var(--text);font-size:12px}.badge.good{background:#304414;color:var(--lime)}.drawer{position:fixed;inset:0 0 0 auto;width:min(620px,100%);overflow:auto;background:#0d1113;border-left:1px solid var(--line);padding:28px;transform:translateX(100%);transition:.2s;z-index:5}.drawer.open{transform:none}.drawer h3{margin-top:28px;border-bottom:1px solid var(--line);padding-bottom:8px}.source{border-left:2px solid var(--lime);padding:8px 12px;margin:10px 0}.source a{color:var(--lime)}.auditbar{position:fixed;bottom:0;left:0;right:0;background:#151c1f;border-top:1px solid var(--line);padding:14px 5vw;display:none;justify-content:space-between;align-items:center;z-index:4}.auditbar.show{display:flex}.methods{display:grid;grid-template-columns:repeat(3,1fr);gap:12px}.method strong{display:block;color:var(--lime);margin-bottom:8px}@media(max-width:800px){.cards{grid-template-columns:repeat(2,1fr)}.methods{grid-template-columns:1fr}table{font-size:12px}th:nth-child(n+5),td:nth-child(n+5){display:none}}
</style></head><body><main>
<div class="eyebrow">Composio agent operations case study</div><h1>Which apps are actually ready to become agent tools?</h1>
<p class="lede">An evidence-grounded research agent examined authentication, API capability, credential access and MCP readiness across 100 applications.</p>
<div class="actions"><button class="btn primary" onclick="document.getElementById('dataset').scrollIntoView()">Explore the dataset</button><button class="btn" onclick="document.getElementById('method').scrollIntoView()">How the agent works</button></div>
<section class="cards"><div class="card"><div class="metric">100/100</div><div class="muted">Apps researched</div></div><div class="card"><div class="metric">18</div><div class="muted">Evidence-finalized</div></div><div class="card"><div class="metric">82</div><div class="muted">Routed to review</div></div><div class="card"><div class="metric">0</div><div class="muted">Operational failures</div></div></section>
<div class="finding">“The API was rarely the only blocker. The harder question was whether a developer could actually obtain and distribute the required credentials.”<small>Unknown does not mean the app lacks support. It means sufficient public evidence was not available for a defensible toolkit verdict. Uncertain records were routed to review.</small></div>
<section id="dataset"><h2>100-app dataset</h2><div class="controls"><input id="q" placeholder="Search apps"><select id="cat"><option value="">All categories</option></select><select id="ver"><option value="">All verdicts</option></select><select id="conf"><option value="">All confidence</option></select><select id="rev"><option value="">All review status</option></select><select id="auth"><option value="">All authentication</option></select><button class="btn" onclick="clearFilters()">Clear filters</button></div><div class="mono" id="count"></div><table><thead><tr><th></th><th>App</th><th>Category</th><th>Authentication</th><th>API capability</th><th>Credential access</th><th>MCP</th><th>Verdict</th><th>Confidence</th><th>Primary review reason</th><th></th></tr></thead><tbody id="rows"></tbody></table></section>
<section id="method"><h2>How the agent works</h2><div class="methods"><div class="method"><strong>01 Discover</strong>Composio searches official documentation.</div><div class="method"><strong>02 Retrieve</strong>Relevant official pages and excerpts are retained.</div><div class="method"><strong>03 Extract</strong>OpenRouter converts evidence into structured fields.</div><div class="method"><strong>04 Normalize</strong>Python preserves unknowns safely.</div><div class="method"><strong>05 Validate</strong>Claims are checked against retained source IDs.</div><div class="method"><strong>06 Finalize or escalate</strong>Supported verdicts are finalized; uncertain cases enter review.</div></div><p class="muted">Model output was never treated as evidence by itself.</p><h2>Engineering notes & limitations</h2><p class="muted">Caching · checkpointed resume · tolerant parsing · source-ID validation · deterministic verdict rules · 43 passing tests · clean Ruff checks.</p><p class="muted">Unknown means insufficient public evidence, not missing functionality. Login-gated portals and credential issuance were often unclear. Only evidence-finalized rows are decisive outcomes; review-required rows need manual verification.</p></section>
</main><aside id="drawer" class="drawer"><button class="btn" onclick="closeDrawer()">Close</button><div id="detail"></div></aside><div id="auditbar" class="auditbar"><span id="selected"></span><button class="btn" onclick="exportAudit('md')">Export Markdown</button><button class="btn" onclick="exportAudit('json')">Export JSON</button><button class="btn" onclick="clearSelection()">Clear selection</button></div>
<script id="data" type="application/json">""" + data + """</script><script>
const apps=JSON.parse(document.getElementById('data').textContent), selected=new Set(JSON.parse(localStorage.getItem('auditSelection')||'[]'));
const map={oauth2:'OAuth 2.0',api_key:'API key',bearer_token:'Bearer token',basic_auth:'Basic authentication',self_serve_free:'Self-serve',workspace_admin_required:'Customer/workspace admin',build_now:'Build now',build_with_customer_credentials:'Customer credentials required',unknown:'Review required'};
const label=v=>v===true?'Yes':v===false?'No':v==null?'Not verified':map[v]||String(v).replaceAll('_',' '); const esc=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
const primary=r=>{const u=r.unresolved_fields||[];for(const [key,msg] of [['credential','Credential path not publicly confirmed'],['authentication','Authentication evidence incomplete'],['documented_api','Documented API not confirmed'],['read_operations','Read/write capability requires verification'],['write_operations','Read/write capability requires verification'],['api_breadth','API breadth could not be established']])if(u.some(x=>x.toLowerCase().includes(key)))return msg;return r.review_status==='review-required'?'Further evidence required':'None'};
const api=r=>{if(r.rest===true&&r.read_operations===true&&r.write_operations===true)return 'REST · Read · Write';if(r.read_operations===true&&r.write_operations!==true)return 'Read-only API';if(r.api_availability?.documented_public_api===true)return 'API documented · Actions unclear';return 'API capability not verified'};
function options(id,key,vals){for(const v of vals){const o=document.createElement('option');o.value=v;o.textContent=label(v);document.getElementById(id).append(o)}}
options('cat','category',[...new Set(apps.map(r=>r.category))].sort());options('ver','buildability_verdict',[...new Set(apps.map(r=>r.buildability_verdict))].sort());options('conf','confidence',[...new Set(apps.map(r=>r.confidence))].sort());options('rev','review_status',[...new Set(apps.map(r=>r.review_status))].sort());options('auth','auth',[...new Set(apps.flatMap(r=>r.authentication?.methods||[]))].sort());
function draw(){const q=document.getElementById('q').value.toLowerCase();const f=apps.filter(r=>(!q||JSON.stringify(r).toLowerCase().includes(q))&&(!cat.value||r.category===cat.value)&&(!ver.value||r.buildability_verdict===ver.value)&&(!conf.value||r.confidence===conf.value)&&(!rev.value||r.review_status===rev.value)&&(!auth.value||(r.authentication?.methods||[]).includes(auth.value))).sort((a,b)=>(a.review_status!==b.review_status? a.review_status==='evidence-finalized'?-1:1:a.name.localeCompare(b.name)));count.textContent=`${f.length} visible results`;rows.innerHTML=f.map(r=>`<tr class="${r.review_status==='evidence-finalized'?'final':''}"><td><input type="checkbox" ${selected.has(r.app_id)?'checked':''} onchange="toggle('${r.app_id}')"></td><td><b>${esc(r.name)}</b></td><td>${esc(r.category)}</td><td>${(r.authentication?.methods||[]).map(label).join(', ')||'Not verified'}</td><td>${api(r)}</td><td>${label(r.credential_access?.independent_developer_access)}</td><td>${label(r.mcp_status?.status)}</td><td><span class="badge ${r.review_status==='evidence-finalized'?'good':''}">${label(r.buildability_verdict)}</span></td><td>${label(r.confidence)}</td><td>${esc(primary(r))}</td><td><button class="btn" onclick="openDrawer('${r.app_id}')">Details</button></td></tr>`).join('')}
function openDrawer(id){const r=apps.find(x=>x.app_id===id), ev=r.evidence_links||[];detail.innerHTML=`<h2>${esc(r.name)}</h2><p class="muted">${esc(r.description||'Description not verified')}</p><h3>Toolkit decision</h3><p>Verdict: <b>${label(r.buildability_verdict)}</b> · Confidence: ${label(r.confidence)}</p><p>Decisive review reason: ${esc(primary(r))}</p><h3>Authentication and access</h3><p>Authentication: ${(r.authentication?.methods||[]).map(label).join(', ')||'Not verified'}<br>Independent developer: ${label(r.credential_access?.independent_developer_access)}<br>Existing customer: ${label(r.credential_access?.existing_customer_access)}<br>Multi-tenant: ${label(r.credential_access?.multi_tenant_integration_access)}</p><h3>API capability</h3><p>Documented API: ${label(r.api_availability?.documented_public_api)} · REST: ${label(r.rest)} · Read: ${label(r.read_operations)} · Write: ${label(r.write_operations)} · Breadth: ${label(r.api_breadth)}</p><h3>Additional capabilities not verified</h3><p>GraphQL: ${label(r.supplementary_capabilities?.graphql)} · Bulk: ${label(r.supplementary_capabilities?.bulk_operations)} · Events: ${label(r.supplementary_capabilities?.webhooks)} · WebSockets: ${label(r.supplementary_capabilities?.websocket)} · SDK: ${label(r.supplementary_capabilities?.sdk_available)} · MCP: ${label(r.mcp_status?.status)}</p><h3>Evidence</h3>${ev.slice(0,3).map(e=>`<div class="source"><b>${esc(e.field||'Evidence')}</b><br>${esc(e.excerpt||e.claim)}<br><a target="_blank" href="${esc(e.url)}">${esc(new URL(e.url).hostname)}</a></div>`).join('')}${ev.length>3?`<p class="muted">View all ${ev.length} sources in the consolidated dataset.</p>`:''}<details><summary>Technical run notes</summary><p>${esc((r.unresolved_fields||[]).join('; '))}</p></details>`;drawer.classList.add('open')}
function closeDrawer(){drawer.classList.remove('open')}function toggle(id){selected.has(id)?selected.delete(id):selected.add(id);localStorage.setItem('auditSelection',JSON.stringify([...selected]));updateAudit();draw()}function updateAudit(){auditbar.classList.toggle('show',selected.size>0);selected.textContent=`${selected.size} apps selected for manual audit`}function clearSelection(){selected.clear();localStorage.setItem('auditSelection','[]');updateAudit();draw()}function clearFilters(){['q','cat','ver','conf','rev','auth'].forEach(id=>document.getElementById(id).value='');draw()}function exportAudit(kind){const list=apps.filter(r=>selected.has(r.app_id));let out=kind==='json'?JSON.stringify({completed:false,apps:list.map(r=>({app_id:r.app_id,name:r.name,verdict:r.buildability_verdict,confidence:r.confidence,evidence:r.evidence_links}))},null,2):list.map(r=>`## ${r.name}\n\nCurrent verdict: ${label(r.buildability_verdict)}\nConfidence: ${label(r.confidence)}\nPrimary review reason: ${primary(r)}\n\n### Decisive claims\n\n- [ ] Documented API — Supported / Unsupported / Unclear\n- [ ] Authentication — Supported / Unsupported / Unclear\n- [ ] Read operations — Supported / Unsupported / Unclear\n- [ ] Write operations — Supported / Unsupported / Unclear\n- [ ] Credential path — Supported / Unsupported / Unclear\n- [ ] Final verdict — Supported / Unsupported / Unclear\n\n### Evidence\n\n${(r.evidence_links||[]).map(e=>`- ${e.url}`).join('\\n')}\n\n### Corrections\n\n### Notes\n`).join('\\n');const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([out],{type:'text/plain'}));a.download=kind==='json'?'manual_audit_selection.json':'manual_audit_selection.md';a.click()}['q','cat','ver','conf','rev','auth'].forEach(id=>document.getElementById(id).oninput=draw);updateAudit();draw();
</script></body></html>"""
    path.write_text(template, encoding="utf-8")
